/* Enhance legibility and user experience with fluid typography */
body {
  font-family: 'Inter', sans-serif; /* Example web font */
  /* 
   * Scales font-size between 1rem (min) and 1.5rem (max).
   * calc(1rem + 2vw) is the preferred fluid value, scaling with viewport width.
   * This ensures text is never too small or too large.
   */
  font-size: clamp(1rem, calc(1rem + 2vw), 1.5rem); 

  /* 
   * Scales line-height between 1.4 (min) and 1.6 (max).
   * calc(1em + 0.2vw) provides fluid line spacing relative to font size and viewport.
   * Crucial for maintaining optimal vertical rhythm and readability.
   */
  line-height: clamp(1.4, calc(1em + 0.2vw), 1.6);
  color: #333;
}

/* Example for a heading with more pronounced scaling */
h1 {
  font-size: clamp(2rem, calc(2rem + 4vw), 4rem);
  line-height: 1.1;
  margin-bottom: 0.5em;
}
